 16→/**
 17→ * Lints and formats the spacing before and after the angle brackets of a type argument list.
 18→ */
 19→public class TypeArgumentListSpacingRule :
 20→    StandardRule("type-argument-list-spacing"),
 21→    Rule.Experimental {
 22→    override fun beforeVisitChildNodes(
 23→        node: ASTNode,
 24→        autoCorrect: Boolean,
 25→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 26→    ) {
 27→        when (node.elementType) {
 28→            ElementType.TYPE_ARGUMENT_LIST -> {
 29→                visitFunctionDeclaration(node, autoCorrect, emit)
 30→                visitInsideTypeArgumentList(node, autoCorrect, emit)
 31→            }
 32→            ElementType.SUPER_TYPE_LIST, ElementType.SUPER_EXPRESSION ->
 33→                visitInsideTypeArgumentList(node, autoCorrect, emit)
 34→        }
 35→    }
 36→
 37→    private fun visitFunctionDeclaration(
 38→        node: ASTNode,
 39→        autoCorrect: Boolean,
 40→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 41→    ) {
 42→        // No whitespace expected before type argument list of function call
 43→        //    val list = listOf <String>()
 44→        node
 45→            .prevLeaf(includeEmpty = true)
 46→            ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
 47→            ?.let { noWhitespaceExpected(it, autoCorrect, emit) }
 48→
 49→        // No whitespace expected after type argument list of function call
 50→        //    val list = listOf<String> ()
 51→        node
 52→            .takeUnless {
 53→                // unless it is part of a type reference:
 54→                //    fun foo(): List<Foo> { ... }
 55→                //    var bar: List<Bar> = emptyList()
 56→                it.isPartOfCompositeElementOfType(ElementType.TYPE_REFERENCE)
 57→            }
 58→            ?.takeUnless {
 59→                // unless it is part of a call expression followed by lambda:
 60→                //    bar<Foo> { ... }
 61→                it.isPartOfCallExpressionFollowedByLambda()
 62→            }
 63→            ?.lastChildNode
 64→            ?.nextLeaf(includeEmpty = true)
 65→            ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
 66→            ?.let { noWhitespaceExpected(it, autoCorrect, emit) }
 67→    }
 68→
 69→    private fun visitInsideTypeArgumentList(
 70→        node: ASTNode,
 71→        autoCorrect: Boolean,
 72→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 73→    ) {
 74→        // No whitespace expected after opening angle bracket of type argument list
 75→        //    val list = listOf< String>()
 76→        node
 77→            .findChildByType(ElementType.LT)
 78→            ?.nextSibling { true }
 79→            ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
 80→            ?.let { noWhitespaceExpected(it, autoCorrect, emit) }
 81→
 82→        // No whitespace expected before closing angle bracket of type argument list
 83→        //    val list = listOf<String >()
 84→        node
 85→            .findChildByType(ElementType.GT)
 86→            ?.prevSibling { true }
 87→            ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
 88→            ?.let { noWhitespaceExpected(it, autoCorrect, emit) }
 89→    }
 90→
 91→    private fun noWhitespaceExpected(
 92→        node: ASTNode,
 93→        autoCorrect: Boolean,
 94→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 95→    ) {
 96→        if (node.text != "") {
 97→            emit(
 98→                node.startOffset,
 99→                "No whitespace expected at this position",
100→                true,
101→            )
102→            if (autoCorrect) {
103→                node.treeParent.removeChild(node)
104→            }
105→        }
106→    }
107→}
108→
109→private fun ASTNode.isPartOfCallExpressionFollowedByLambda(): Boolean =
110→    parent(findCompositeElementOfType(ElementType.CALL_EXPRESSION))
111→        ?.takeIf { it.elementType == ElementType.CALL_EXPRESSION }
112→        ?.findChildByType(ElementType.LAMBDA_ARGUMENT)
113→        .let { it != null }
114→
115→public val TYPE_ARGUMENT_LIST_SPACING_RULE_ID: RuleId = TypeArgumentListSpacingRule().ruleId
